import{_ as t,o as e,c as o,a0 as d}from"./chunks/framework.jwovEGr5.js";const p=JSON.parse('{"title":"Linux系统通用备份恢复方法","description":"","frontmatter":{"title":"Linux系统通用备份恢复方法","date":"2016-06-16T01:13:33.000Z","category":"Linux","tags":["Linux"]},"headers":[],"relativePath":"posts/linux-xi-tong-tong-yong-bei-fen-hui-fu-fang-fa.md","filePath":"posts/linux-xi-tong-tong-yong-bei-fen-hui-fu-fang-fa.md","lastUpdated":1783006593000}'),r={name:"posts/linux-xi-tong-tong-yong-bei-fen-hui-fu-fang-fa.md"};function c(n,a,s,i,u,b){return e(),o("div",null,[...a[0]||(a[0]=[d('<p>用电脑多了，难免会出现系统故障的情况，如果不想经常重装系统，特别是开发人员，每次重装系统都是噩梦，因为要安装很多很多软件，配置各种参数、环境变量，这时候备份恢复系统的工作尤为重要。</p><p>Win系统的备份用Ghost，各种一键Ghost很成熟，那么Linux系统备份用什么呢？</p><p>有人说，也用Ghost，有人说，我直接dd整个硬盘镜像，再或者用CloneZilla再生龙，其实最好用的就是一个Linux的启动镜像，简单，可靠。</p><p>用Ghost备份Linux速度慢稳定性差，因为文件系统和Win差异很大，哪怕用分区备份的方式都不可靠，试过几次后我就彻底放弃了</p><p>dd命令看似可靠，但速度太慢了，而且局限性很大，如果分区大小不同，如果用来迁移Linux系统或者换了一个大硬盘或者系统换一个分区，都不行。</p><p>再生龙CloneZilla功能很强大，本身也是一个U盘或者光盘启动的Linux系统，但配置太复杂了，各种配置选择一堆一堆。</p><p>其实，只是备份恢复系统的话，tar命令就可以了，在系统里面如果要备份整个系统是不可能的，自己打包自己听着就不靠谱，这时候就需要一个能从光盘或者U盘启动的Linux，这个Linux的版本最好和需要备份的Linux一致，比如我是32位的Ubuntu 14.04，那最好用32位的Ubuntu 14.04的iso启动镜像启动，选择试用就行了。</p><p><img src="https://raw.githubusercontent.com/white-alone/blog_img/master/Linux%E7%B3%BB%E7%BB%9F%E9%80%9A%E7%94%A8%E5%A4%87%E4%BB%BD%E6%81%A2%E5%A4%8D%E6%96%B9%E6%B3%95/1591024098690.png" alt=""></p><p>系统启动以后，打开Terminal终端</p><p><img src="https://raw.githubusercontent.com/white-alone/blog_img/master/Linux%E7%B3%BB%E7%BB%9F%E9%80%9A%E7%94%A8%E5%A4%87%E4%BB%BD%E6%81%A2%E5%A4%8D%E6%96%B9%E6%B3%95/1591024098691.png" alt=""></p><h3 id="sudo-passwd-root" tabindex="-1">sudo passwd root <a class="header-anchor" href="#sudo-passwd-root" aria-label="Permalink to &quot;sudo passwd root&quot;">​</a></h3><h3 id="su" tabindex="-1">su - <a class="header-anchor" href="#su" aria-label="Permalink to &quot;su -&quot;">​</a></h3><p>却换到root用户</p><p><img src="https://raw.githubusercontent.com/white-alone/blog_img/master/Linux%E7%B3%BB%E7%BB%9F%E9%80%9A%E7%94%A8%E5%A4%87%E4%BB%BD%E6%81%A2%E5%A4%8D%E6%96%B9%E6%B3%95/1591024098692.png" alt=""></p><h3 id="fdisk-l-dev-sda" tabindex="-1">fdisk -l /dev/sda <a class="header-anchor" href="#fdisk-l-dev-sda" aria-label="Permalink to &quot;fdisk -l /dev/sda&quot;">​</a></h3><p>检查硬盘分区情况，看看要备份的系统状况，这里要备份的是sda1分区</p><p><img src="https://raw.githubusercontent.com/white-alone/blog_img/master/Linux%E7%B3%BB%E7%BB%9F%E9%80%9A%E7%94%A8%E5%A4%87%E4%BB%BD%E6%81%A2%E5%A4%8D%E6%96%B9%E6%B3%95/1591024098735.png" alt=""></p><h3 id="mkdir-mnt-sda1" tabindex="-1">mkdir /mnt/sda1 <a class="header-anchor" href="#mkdir-mnt-sda1" aria-label="Permalink to &quot;mkdir /mnt/sda1&quot;">​</a></h3><h3 id="mount-dev-sda1-mnt-sda1" tabindex="-1">mount /dev/sda1 /mnt/sda1 <a class="header-anchor" href="#mount-dev-sda1-mnt-sda1" aria-label="Permalink to &quot;mount /dev/sda1 /mnt/sda1&quot;">​</a></h3><h3 id="cd-mnt-sda1" tabindex="-1">cd /mnt/sda1 <a class="header-anchor" href="#cd-mnt-sda1" aria-label="Permalink to &quot;cd /mnt/sda1&quot;">​</a></h3><h3 id="ls" tabindex="-1">ls <a class="header-anchor" href="#ls" aria-label="Permalink to &quot;ls&quot;">​</a></h3><p><img src="https://raw.githubusercontent.com/white-alone/blog_img/master/Linux%E7%B3%BB%E7%BB%9F%E9%80%9A%E7%94%A8%E5%A4%87%E4%BB%BD%E6%81%A2%E5%A4%8D%E6%96%B9%E6%B3%95/1591024098736.png" alt=""></p><p>确认挂载的目录是要备份的系统根目录，如果有其他的分区需要挂载到该系统根目录，记得挂载</p><p>之后用tar命令打包备份，如果有多个分区最好备份到另一个分区，如果只有一个分区怎么办呢？OK</p><h3 id="tar-czvf-backup-tar-exclude-backup-tar" tabindex="-1">tar -czvf backup.tar ./ --exclude backup.tar <a class="header-anchor" href="#tar-czvf-backup-tar-exclude-backup-tar" aria-label="Permalink to &quot;tar -czvf backup.tar ./ --exclude backup.tar&quot;">​</a></h3><p>打包备份当前目录到backup.tar，但要排除backup.tar文件，不然回把这个备份文件一起打包进去，打包的备份文件为当时的文件。总之，又是自己打包自己，所以需要用<code>--exclude</code>排除。</p><h3 id="du-sh-backup-tar" tabindex="-1">du -sh backup.tar <a class="header-anchor" href="#du-sh-backup-tar" aria-label="Permalink to &quot;du -sh backup.tar&quot;">​</a></h3><h3 id="df-h" tabindex="-1">df -h <a class="header-anchor" href="#df-h" aria-label="Permalink to &quot;df -h&quot;">​</a></h3><p><img src="https://raw.githubusercontent.com/white-alone/blog_img/master/Linux%E7%B3%BB%E7%BB%9F%E9%80%9A%E7%94%A8%E5%A4%87%E4%BB%BD%E6%81%A2%E5%A4%8D%E6%96%B9%E6%B3%95/1591024098737.png" alt=""></p><p>打包后可以看大小，打包前最好也用<code>df -h</code>看下<code>/mnt/sda1</code>的大小，差不多不太离谱就好。</p><p>这时候就可以将备份的<code>backup.tar</code>拷贝走，保存好，可以重启进入硬盘的系统拷贝，也能在这个系统用<code>scp</code>命令拷到别的linux机器，或者插一个U盘拷进去都可以。</p><p>备份的这个<code>backup.tar</code>可以用来恢复系统，也可以给其他机器部署这个配置好的<code>Linux</code>系统，这就是Linux的优点，不依赖硬件。</p><p>如果要部署到另一台机器，先用启动光盘或者U盘启动系统，如果没有事先分好分区，就用<code>fdisk</code>给目标机器分区，之后用<code>mkfs.ext4</code>命令或者其他格式文件系统的<code>mkfs</code>命令格式化分区，记得<code>mkswap</code>分区，除非你不想用<code>swap</code>分区。</p><p>格式化好之后，创建文件夹，然后挂载，比如挂载到<code>/mnt/sda1</code>，如果是恢复系统也可以直接先格式化要恢复的系统分区，因为用<code>rm -rf</code>删除所有目录速度太慢，即使用<code>rsync</code>的方法也不如直接<code>mkfs</code>格式化快。</p><p>将<code>backup.tar</code>拷到<code>/mnt/sda1</code>，然后进入这个目录</p><p><img src="https://raw.githubusercontent.com/white-alone/blog_img/master/Linux%E7%B3%BB%E7%BB%9F%E9%80%9A%E7%94%A8%E5%A4%87%E4%BB%BD%E6%81%A2%E5%A4%8D%E6%96%B9%E6%B3%95/1591024098759.png" alt=""></p><h3 id="tar-zxvf-backup-tar" tabindex="-1">tar -zxvf backup.tar <a class="header-anchor" href="#tar-zxvf-backup-tar" aria-label="Permalink to &quot;tar -zxvf backup.tar&quot;">​</a></h3><p>解包，解包完成后看下，有没有少什么目录</p><p><img src="https://raw.githubusercontent.com/white-alone/blog_img/master/Linux%E7%B3%BB%E7%BB%9F%E9%80%9A%E7%94%A8%E5%A4%87%E4%BB%BD%E6%81%A2%E5%A4%8D%E6%96%B9%E6%B3%95/1591024098760.png" alt=""></p><p>这样就完了么？当然没有，还需要修改<code>fstab</code>和<code>grub</code>，不然挂载会有问题</p><h3 id="vi-etc-fstab" tabindex="-1">vi etc/fstab <a class="header-anchor" href="#vi-etc-fstab" aria-label="Permalink to &quot;vi etc/fstab&quot;">​</a></h3><p><img src="https://raw.githubusercontent.com/white-alone/blog_img/master/Linux%E7%B3%BB%E7%BB%9F%E9%80%9A%E7%94%A8%E5%A4%87%E4%BB%BD%E6%81%A2%E5%A4%8D%E6%96%B9%E6%B3%95/1591024098761.png" alt=""></p><p>将fstab分区挂载改成自己所选的分区，如果是用<code>UUID</code>做区分，用<code>blkid</code>看当前硬盘分区的<code>UUID</code></p><p><img src="https://raw.githubusercontent.com/white-alone/blog_img/master/Linux%E7%B3%BB%E7%BB%9F%E9%80%9A%E7%94%A8%E5%A4%87%E4%BB%BD%E6%81%A2%E5%A4%8D%E6%96%B9%E6%B3%95/1591024098762.png" alt=""></p><p>修改完<code>fstab</code>之后，还要修改<code>grub</code>配置文件并重装<code>grub</code>，不然可能会导致系统卡在grub命令界面无法启动。</p><h3 id="vi-boot-grub-grub-cfg" tabindex="-1">vi /boot/grub/grub.cfg <a class="header-anchor" href="#vi-boot-grub-grub-cfg" aria-label="Permalink to &quot;vi /boot/grub/grub.cfg&quot;">​</a></h3><p><img src="https://raw.githubusercontent.com/white-alone/blog_img/master/Linux%E7%B3%BB%E7%BB%9F%E9%80%9A%E7%94%A8%E5%A4%87%E4%BB%BD%E6%81%A2%E5%A4%8D%E6%96%B9%E6%B3%95/1591024098763.png" alt=""></p><p>注意<code>root</code>后面跟的<code>UUID</code>是不是和刚才<code>blkid</code>看到的启动分区一致，如不一致，用<code>sed</code>替换或者直接将<code>blkid</code>看到<code>UUID</code>复制替换<code>grub.cfg</code>中的<code>UUID</code></p><h3 id="sed-i-s-blkid看到的-grub-cfg中的-g-boot-grub-grub-cfg" tabindex="-1">sed -i &quot;s/blkid看到的/grub.cfg中的/g&quot; boot/grub/grub.cfg <a class="header-anchor" href="#sed-i-s-blkid看到的-grub-cfg中的-g-boot-grub-grub-cfg" aria-label="Permalink to &quot;sed -i &quot;s/blkid看到的/grub.cfg中的/g&quot; boot/grub/grub.cfg&quot;">​</a></h3><h3 id="vi-boot-grub-grub-cfg-1" tabindex="-1">vi /boot/grub/grub.cfg <a class="header-anchor" href="#vi-boot-grub-grub-cfg-1" aria-label="Permalink to &quot;vi /boot/grub/grub.cfg&quot;">​</a></h3><p>再检查一次，另外如果启动分区不是<code>sda1</code>，还需要调整前面的<code>set</code>和<code>menuentry</code>中的启动选项，<code>hd0,hd1,hd2,hd3</code>对应<code>sda,sdb,sdc,sdd</code>依此类推，<code>msdos1,msdos2,msdos3</code>对应<code>sdx1,sdx2,sdx3</code>依此类推</p><p><img src="https://raw.githubusercontent.com/white-alone/blog_img/master/Linux%E7%B3%BB%E7%BB%9F%E9%80%9A%E7%94%A8%E5%A4%87%E4%BB%BD%E6%81%A2%E5%A4%8D%E6%96%B9%E6%B3%95/1591024098768.png" alt=""></p><p>grub配置修改完成后，安装grub到硬盘mbr</p><h3 id="grub-install-root-directory-mnt-sda1-dev-sda" tabindex="-1">grub-install --root-directory=/mnt/sda1 /dev/sda <a class="header-anchor" href="#grub-install-root-directory-mnt-sda1-dev-sda" aria-label="Permalink to &quot;grub-install --root-directory=/mnt/sda1 /dev/sda&quot;">​</a></h3><p>指定<code>boot</code>根目录路径，安装到<code>/dev/sda</code>表面安装到硬盘<code>sda</code>的<code>mbr</code>，<code>sdx</code>后面不带数字就表明安装到<code>mbr</code>，否则就是安装到分区</p><p><img src="https://raw.githubusercontent.com/white-alone/blog_img/master/Linux%E7%B3%BB%E7%BB%9F%E9%80%9A%E7%94%A8%E5%A4%87%E4%BB%BD%E6%81%A2%E5%A4%8D%E6%96%B9%E6%B3%95/1591024098769.png" alt=""></p><p>注意，如果是用32位系统去安装64位系统的grub会报错，或者grub版本差异太大，安装也会报错，尽量保证系统版本和grub版本的一致性。</p><p>如果不一致怎么办？也可以，用chroot进到目标系统，再安装grub</p><h3 id="chmod-1777-mnt-sda1-tmp" tabindex="-1">chmod 1777 /mnt/sda1/tmp/ <a class="header-anchor" href="#chmod-1777-mnt-sda1-tmp" aria-label="Permalink to &quot;chmod 1777 /mnt/sda1/tmp/&quot;">​</a></h3><h3 id="mount-t-proc-proc-mnt-sda1-proc" tabindex="-1">mount -t proc proc /mnt/sda1/proc <a class="header-anchor" href="#mount-t-proc-proc-mnt-sda1-proc" aria-label="Permalink to &quot;mount -t proc proc /mnt/sda1/proc&quot;">​</a></h3><h3 id="mount-o-bind-dev-mnt-sda1-dev" tabindex="-1">mount -o bind /dev /mnt/sda1/dev/ <a class="header-anchor" href="#mount-o-bind-dev-mnt-sda1-dev" aria-label="Permalink to &quot;mount -o bind /dev /mnt/sda1/dev/&quot;">​</a></h3><h3 id="chroot-mnt-sda1-bin-bash" tabindex="-1">chroot /mnt/sda1 /bin/bash <a class="header-anchor" href="#chroot-mnt-sda1-bin-bash" aria-label="Permalink to &quot;chroot /mnt/sda1 /bin/bash&quot;">​</a></h3><h3 id="grub-install-dev-sda" tabindex="-1">grub-install /dev/sda <a class="header-anchor" href="#grub-install-dev-sda" aria-label="Permalink to &quot;grub-install /dev/sda&quot;">​</a></h3><p><img src="https://raw.githubusercontent.com/white-alone/blog_img/master/Linux%E7%B3%BB%E7%BB%9F%E9%80%9A%E7%94%A8%E5%A4%87%E4%BB%BD%E6%81%A2%E5%A4%8D%E6%96%B9%E6%B3%95/1591024098770.png" alt=""></p><p>之后退出然后重启即可</p><p><img src="https://raw.githubusercontent.com/white-alone/blog_img/master/Linux%E7%B3%BB%E7%BB%9F%E9%80%9A%E7%94%A8%E5%A4%87%E4%BB%BD%E6%81%A2%E5%A4%8D%E6%96%B9%E6%B3%95/1591024098771.png" alt=""></p><p><img src="https://raw.githubusercontent.com/white-alone/blog_img/master/Linux%E7%B3%BB%E7%BB%9F%E9%80%9A%E7%94%A8%E5%A4%87%E4%BB%BD%E6%81%A2%E5%A4%8D%E6%96%B9%E6%B3%95/1591024098772.png" alt=""></p><p>如果系统无法启动，卡在<code>grub</code>界面比较常见，或者启动后文件系统无法挂载，请用光盘或者U盘启动linux，挂载分区检查<code>fstab</code>和<code>grub.cfg</code>，再重新装<code>grub</code>，问题基本都出在这里。</p><p>最后，还是建议最好在机器里面安装双系统，这样可以很方便的互相备份恢复。</p><p>这种做法还可以将物理机迁移到虚拟机，也可以将虚拟机迁移到物理机，不过需要注意的是虚拟机增强工具，比如<code>vmware-tools</code>，物理机是不需要的，记得卸载。</p>',70)])])}const h=t(r,[["render",c]]);export{p as __pageData,h as default};
